import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { loginUser } from "../service/apiservice";

function LoginForm() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("user");   // ✅ NEW ROLE STATE
  const [message, setMessage] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [user, setUser] = useState(null);
  const [error, setError] = useState("");

  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      // ✅ Pass role also
      const data = await loginUser(email, password);
      const user=data.user;

      
        localStorage.setItem("user", JSON.stringify(user));
        

        // ✅ Navigate based on role
        if (user.role === "admin") {
          navigate("/AdminDashboard");
        } else {
          navigate("/UserDash");
        }
      
      }
     catch (err) {
      setError("Server error, please try again later");
    }
  };

  const handleForgotPassword = () => {
    navigate("/forgotpassword");
  };

  const togglePassword = () => {
    setShowPassword(!showPassword);
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.heading}>Welcome Back!</h2>
        <p style={styles.subHeading}>Login to your account</p>

        <form onSubmit={handleSubmit}>
          {/* Email */}
          <div style={styles.inputContainer}>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="Email"
              required
              style={styles.input}
            />
          </div>

          {/* Password */}
          <div style={styles.inputContainer}>
            <input
              type={showPassword ? "text" : "password"}
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Password"
              required
              style={styles.input}
            />
            <button
              type="button"
              onClick={togglePassword}
              style={styles.toggleButton}
            >
              {showPassword ? "Hide" : "Show"}
            </button>
          </div>

          

          {/* Forgot Password */}
          <div style={styles.forgotPassword}>
            <button
              type="button"
              onClick={handleForgotPassword}
              style={styles.linkButton}
            >
              Forgot Password?
            </button>
          </div>

          <button type="submit" style={styles.loginButton}>
            Login
          </button>

          {(message || error) && (
            <p style={styles.message}>{message || error}</p>
          )}

          <div style={styles.register}>
            <b>Don't have an account?</b>{" "}
            <button
              type="button"
              style={styles.linkButton}
              onClick={() => navigate("/Registration")}
            >
              Register here
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

// Styles remain unchanged
const styles = {
  container: {
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    height: "100vh",
    background: "linear-gradient(135deg, #91146aff, #764ba2)",
    fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
  },
  card: {
    background: "#cbb8b8ff",
    padding: "40px 30px",
    borderRadius: "15px",
    boxShadow: "0 10px 25px rgba(0,0,0,0.2)",
    width: "360px",
    textAlign: "center",
  },
  heading: {
    margin: 0,
    fontSize: "28px",
    color: "#333",
    marginBottom: "5px",
  },
  subHeading: {
    fontSize: "14px",
    color: "#4d4646ff",
    marginBottom: "25px",
  },
  inputContainer: {
    position: "relative",
    marginBottom: "20px",
  },
  input: {
    width: "100%",
    padding: "12px",
    borderRadius: "8px",
    border: "1px solid #ccc",
    fontSize: "14px",
    outline: "none",
    transition: "0.3s",
  },
  toggleButton: {
    position: "absolute",
    top: "50%",
    right: "12px",
    transform: "translateY(-50%)",
    background: "none",
    border: "none",
    color: "#1f2a59ff",
    cursor: "pointer",
    fontSize: "14px",
  },
  forgotPassword: {
    textAlign: "right",
    marginBottom: "20px",
  },
  linkButton: {
    background: "none",
    border: "none",
    color: "#243a99ff",
    cursor: "pointer",
    textDecoration: "underline",
    fontSize: "14px",
  },
  loginButton: {
    width: "100%",
    padding: "12px",
    background: "linear-gradient(90deg, #436f35ff, #266009cc)",
    color: "#fff",
    fontSize: "16px",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer",
    transition: "0.3s",
  },
  message: {
    color: "red",
    marginTop: "15px",
    fontSize: "14px",
  },
  register: {
    marginTop: "20px",
    fontSize: "14px",
    color: "#555",
  },
};

export default LoginForm;
